import{_ as c,C as p,o,c as h,a7 as l,b as s,w as t,a,E as d,a8 as r,j as n}from"./chunks/framework.Doa-uGBm.js";const E=JSON.parse('{"title":"Cynefin Framework Diagram (v<MERMAID_RELEASE_VERSION>+)","description":"","frontmatter":{"editLink":"https://github.com/mermaid-js/mermaid/edit/develop/packages/mermaid/src/docs/syntax/cynefin.md","head":[["link",{"rel":"canonical","href":"https://mermaid.ai/open-source/syntax/cynefin.html"}]]},"headers":[],"relativePath":"syntax/cynefin.md","filePath":"syntax/cynefin.md"}'),m={name:"syntax/cynefin.md"};function u(f,e,g,b,y,k){const i=p("Mermaid");return o(),h("div",null,[e[3]||(e[3]=l(`<h1 id="cynefin-framework-diagram-v-mermaid-release-version" tabindex="-1">Cynefin Framework Diagram (v&lt;MERMAID_RELEASE_VERSION&gt;+) <a class="header-anchor" href="#cynefin-framework-diagram-v-mermaid-release-version" aria-label="Permalink to &quot;Cynefin Framework Diagram (v\\&lt;MERMAID_RELEASE_VERSION&gt;+)&quot;">​</a></h1><blockquote><p>The Cynefin framework is a sense-making framework created by <a href="https://en.wikipedia.org/wiki/Dave_Snowden" target="_blank" rel="noreferrer">Dave Snowden</a> that categorizes problems into five complexity domains. It helps teams match their response to the nature of the situation they are facing. The name is Welsh for &quot;place&quot; or &quot;habitat&quot;.</p></blockquote><p>You can read more at <a href="https://thecynefin.co/about-us/about-cynefin-framework" target="_blank" rel="noreferrer">The Cynefin Co</a>.</p><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>The Cynefin framework divides the world into five domains, each with its own decision-making approach:</p><ul><li><strong>Clear</strong> (formerly Obvious/Simple): Cause and effect are obvious. Sense → Categorise → Respond. Apply <strong>best practices</strong>.</li><li><strong>Complicated</strong>: Cause and effect require analysis or expertise. Sense → Analyse → Respond. Apply <strong>good practices</strong>.</li><li><strong>Complex</strong>: Cause and effect can only be deduced in retrospect. Probe → Sense → Respond. Apply <strong>emergent practices</strong>.</li><li><strong>Chaotic</strong>: No perceivable cause and effect. Act → Sense → Respond. Apply <strong>novel practices</strong>.</li><li><strong>Confusion</strong> (or Disorder): You do not know which domain you are in. The goal is to move items out of this state into one of the other four.</li></ul><p>The signature visual feature is the wavy, organic boundary between the ordered (Clear, Complicated) and unordered (Complex, Chaotic) halves, and the &quot;cliff&quot; between Clear and Chaotic representing the risk of complacency leading to crisis.</p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to &quot;Syntax&quot;">​</a></h2><p>A Cynefin diagram is declared with <code>cynefin-beta</code> followed by domain blocks and optional transitions.</p><div class="language-md vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">md</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cynefin-beta</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">title Optional Diagram Title</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">complex</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;Item label&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;Another item&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">complicated</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;Expert analysis needed&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">clear</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;Known procedure&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">chaotic</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;Crisis response&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">confusion</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;Item of unknown domain&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">complex --&gt; complicated : &quot;Pattern identified&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">clear --&gt; chaotic : &quot;Complacency&quot;</span></span></code></pre></div><h3 id="keywords" tabindex="-1">Keywords <a class="header-anchor" href="#keywords" aria-label="Permalink to &quot;Keywords&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Keyword</th><th>Meaning</th></tr></thead><tbody><tr><td><code>cynefin-beta</code></td><td>Diagram type declaration (required, first line after any front matter)</td></tr><tr><td><code>title</code></td><td>Optional diagram title</td></tr><tr><td><code>complex</code></td><td>Opens the Complex domain block</td></tr><tr><td><code>complicated</code></td><td>Opens the Complicated domain block</td></tr><tr><td><code>clear</code></td><td>Opens the Clear domain block</td></tr><tr><td><code>chaotic</code></td><td>Opens the Chaotic domain block</td></tr><tr><td><code>confusion</code></td><td>Opens the Confusion / Disorder domain block</td></tr><tr><td><code>--&gt;</code></td><td>Declares a transition from one domain to another</td></tr></tbody></table><h3 id="items" tabindex="-1">Items <a class="header-anchor" href="#items" aria-label="Permalink to &quot;Items&quot;">​</a></h3><p>Items are quoted string labels placed on their own lines inside a domain block. Each item renders as a text badge within the domain region.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>complex</span></span>
<span class="line"><span>  &quot;Investigate root cause&quot;</span></span>
<span class="line"><span>  &quot;Run chaos experiment&quot;</span></span></code></pre></div><p>Keep per-domain item lists short — the quadrants have fixed layout and long lists can visually overflow their boxes. The confusion ellipse caps at three items and shows a <code>+N more</code> badge; the four quadrant domains do not clip, so prefer a handful of items each.</p><h3 id="transitions" tabindex="-1">Transitions <a class="header-anchor" href="#transitions" aria-label="Permalink to &quot;Transitions&quot;">​</a></h3><p>Transitions represent movement of items between domains over time. They are declared at the top level using <code>--&gt;</code> between two domain names, with an optional label.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>complex --&gt; complicated : &quot;Pattern identified&quot;</span></span>
<span class="line"><span>clear --&gt; chaotic : &quot;Complacency&quot;</span></span>
<span class="line"><span>chaotic --&gt; complex : &quot;Stabilized&quot;</span></span></code></pre></div><p>Common transitions:</p><ul><li><strong>Complex → Complicated</strong>: An emerging pattern has become understood and can now be analyzed.</li><li><strong>Chaotic → Complex</strong>: A crisis has been stabilized enough to begin probing.</li><li><strong>Clear → Chaotic</strong>: Complacency or over-constraint has led to collapse (the &quot;cliff&quot;).</li><li><strong>Complicated → Clear</strong>: Analysis has codified a solution into a standard practice.</li></ul><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><h3 id="basic-example" tabindex="-1">Basic example <a class="header-anchor" href="#basic-example" aria-label="Permalink to &quot;Basic example&quot;">​</a></h3>`,23)),(o(),s(r,null,{default:t(()=>[d(i,{id:"mermaid-183",showCode:!0,graph:"cynefin-beta%0A%20%20title%20Incident%20Response%0A%0A%20%20complex%0A%20%20%20%20%22Investigate%20root%20cause%22%0A%20%20%20%20%22Run%20chaos%20experiment%22%0A%0A%20%20complicated%0A%20%20%20%20%22Analyze%20performance%20data%22%0A%20%20%20%20%22Expert%20review%20needed%22%0A%0A%20%20clear%0A%20%20%20%20%22Restart%20service%22%0A%20%20%20%20%22Apply%20known%20fix%22%0A%0A%20%20chaotic%0A%20%20%20%20%22Page%20on-call%20immediately%22%0A%0A%20%20confusion%0A%20%20%20%20%22Unknown%20failure%20mode%22%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[a(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=n("h3",{id:"with-transitions",tabindex:"-1"},[a("With transitions "),n("a",{class:"header-anchor",href:"#with-transitions","aria-label":'Permalink to "With transitions"'},"​")],-1)),(o(),s(r,null,{default:t(()=>[d(i,{id:"mermaid-187",showCode:!0,graph:"cynefin-beta%0A%20%20title%20Strategy%20Categorization%0A%0A%20%20complex%0A%20%20%20%20%22Market%20research%22%0A%0A%20%20complicated%0A%20%20%20%20%22Competitive%20analysis%22%0A%0A%20%20clear%0A%20%20%20%20%22Standard%20pricing%22%0A%0A%20%20chaotic%0A%20%20%20%20%22Crisis%20management%22%0A%0A%20%20complex%20--%3E%20complicated%20%3A%20%22Pattern%20identified%22%0A%20%20complicated%20--%3E%20clear%20%3A%20%22Best%20practice%20codified%22%0A%20%20clear%20--%3E%20chaotic%20%3A%20%22Complacency%22%0A%20%20chaotic%20--%3E%20complex%20%3A%20%22Stabilized%22%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[a(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=n("h3",{id:"empty-framework",tabindex:"-1"},[a("Empty framework "),n("a",{class:"header-anchor",href:"#empty-framework","aria-label":'Permalink to "Empty framework"'},"​")],-1)),e[6]||(e[6]=n("p",null,"The domains themselves render even with no items, useful as a teaching or worksheet template.",-1)),(o(),s(r,null,{default:t(()=>[d(i,{id:"mermaid-194",showCode:!0,graph:"cynefin-beta%0A%20%20title%20Cynefin%20Framework%0A%0A%20%20complex%0A%20%20complicated%0A%20%20clear%0A%20%20chaotic%0A"})]),fallback:t(()=>[...e[2]||(e[2]=[a(" Loading... ",-1)])]),_:1})),e[7]||(e[7]=l(`<h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Cynefin diagrams accept the following configuration under the <code>cynefin</code> key in the mermaid config:</p><table tabindex="0"><thead><tr><th>Option</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>width</code></td><td>number</td><td><code>800</code></td><td>Width of the diagram in pixels</td></tr><tr><td><code>height</code></td><td>number</td><td><code>600</code></td><td>Height of the diagram in pixels</td></tr><tr><td><code>padding</code></td><td>number</td><td><code>40</code></td><td>Padding around the diagram</td></tr><tr><td><code>showDomainDescriptions</code></td><td>boolean</td><td><code>true</code></td><td>Show decision model and practice type subtitles per domain</td></tr><tr><td><code>boundaryAmplitude</code></td><td>number</td><td><code>8</code></td><td>Waviness amplitude of domain boundaries in pixels (set to <code>0</code> for straight lines)</td></tr><tr><td><code>seed</code></td><td>number</td><td><code>0</code></td><td>Deterministic seed for boundary waviness. <code>0</code> (default) hashes the diagram&#39;s SVG id so each diagram looks unique. Set any non-zero number to lock the waviness across renders — required for stable visual regression tests.</td></tr></tbody></table><p>Example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%%{init: {&#39;cynefin&#39;: {&#39;width&#39;: 1000, &#39;showDomainDescriptions&#39;: false}}}%%</span></span>
<span class="line"><span>cynefin-beta</span></span>
<span class="line"><span>  complex</span></span>
<span class="line"><span>    &quot;Adaptive work&quot;</span></span></code></pre></div><h2 id="theming" tabindex="-1">Theming <a class="header-anchor" href="#theming" aria-label="Permalink to &quot;Theming&quot;">​</a></h2><p>Cynefin diagrams use the following theme variables, which can be overridden via <code>themeVariables.cynefin</code>:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>complexBg</code></td><td>Background color for the Complex domain</td></tr><tr><td><code>complicatedBg</code></td><td>Background color for the Complicated domain</td></tr><tr><td><code>clearBg</code></td><td>Background color for the Clear domain</td></tr><tr><td><code>chaoticBg</code></td><td>Background color for the Chaotic domain</td></tr><tr><td><code>confusionBg</code></td><td>Background color for the Confusion center region</td></tr><tr><td><code>boundaryColor</code></td><td>Color of the wavy domain boundaries</td></tr><tr><td><code>boundaryWidth</code></td><td>Stroke width of the boundaries</td></tr><tr><td><code>cliffColor</code></td><td>Color of the Clear/Chaotic cliff</td></tr><tr><td><code>cliffWidth</code></td><td>Stroke width of the cliff</td></tr><tr><td><code>arrowColor</code></td><td>Color of transition arrows</td></tr><tr><td><code>arrowWidth</code></td><td>Stroke width of transition arrows</td></tr><tr><td><code>labelColor</code></td><td>Color of domain name labels</td></tr><tr><td><code>textColor</code></td><td>Color of item and subtitle text</td></tr><tr><td><code>domainFontSize</code></td><td>Font size of domain name labels</td></tr><tr><td><code>itemFontSize</code></td><td>Font size of item badges and subtitles</td></tr></tbody></table><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Domain names are fixed keywords. Only <code>complex</code>, <code>complicated</code>, <code>clear</code>, <code>chaotic</code>, and <code>confusion</code> are recognized.</li><li>Domains can be declared in any order; their position in the diagram is always the same (Complex top-left, Complicated top-right, Chaotic bottom-left, Clear bottom-right, Confusion center).</li><li>The <code>confusion</code> domain has a compact center ellipse. Up to 3 items are shown inside it; if more are provided a <code>+N more</code> overflow badge is displayed. In practice, the confusion domain should contain very few items — its purpose is to surface unknowns so they can be moved to one of the four main domains.</li><li>Self-loop transitions (e.g. <code>complex --&gt; complex</code>) are silently ignored. Transitions must connect two different domains.</li><li>Handdrawn mode is not currently supported.</li><li>The wavy boundary rendering is deterministic: the same input always produces the same diagram, so diffs are stable across builds.</li></ul><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><p>Cynefin diagrams support the standard mermaid accessibility directives:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cynefin-beta</span></span>
<span class="line"><span>  accTitle: Cynefin framework for software delivery decisions</span></span>
<span class="line"><span>  accDescr: A Cynefin map categorizing software tasks by complexity domain</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  complex</span></span>
<span class="line"><span>    &quot;New feature discovery&quot;</span></span></code></pre></div>`,13))])}const w=c(m,[["render",u]]);export{E as __pageData,w as default};
